// NewExtractionResult creates a ExtractionResult with optional parameters.
func NewExtractionResult(opts ...ExtractionResultOption) *ExtractionResult {
	c := &ExtractionResult{
		Content:             "",
		MimeType:            "",
		Metadata:            Metadata{},
		Tables:              nil,
		DetectedLanguages:   nil,
		Chunks:              nil,
		Images:              nil,
		Pages:               nil,
		Elements:            nil,
		DjotContent:         nil,
		OcrElements:         nil,
		Document:            nil,
		QualityScore:        nil,
		ProcessingWarnings:  nil,
		Annotations:         nil,
		Children:            nil,
		Uris:                nil,
		StructuredOutput:    nil,
		CodeIntelligence:    nil,
		LlmUsage:            nil,
		FormattedContent:    nil,
		OcrInternalDocument: nil,
	}
	for _, opt := range opts {
		opt(c)
	}
	return c
}

// A single file extracted from an archive.
//
// When archives (ZIP, TAR, 7Z, GZIP) are extracted with recursive extraction
// enabled, each processable file produces its own full `ExtractionResult`.
type ArchiveEntry struct {
	// Archive-relative file path (e.g. "folder/document.pdf").
	Path string `json:"path"`
	// Detected MIME type of the file.
	MimeType string `json:"mime_type"`
	// Full extraction result for this file.
	Result ExtractionResult `json:"result"`
}

// A non-fatal warning from a processing pipeline stage.
//
// Captures errors from optional features that don't prevent extraction
// but may indicate degraded results.
type ProcessingWarning struct {
	// The pipeline stage or feature that produced this warning
	// (e.g., "embedding", "chunking", "language_detection", "output_format").
	Source string `json:"source"`
	// Human-readable description of what went wrong.
	Message string `json:"message"`
}

// Token usage and cost data for a single LLM call made during extraction.
//
// Populated when VLM OCR, structured extraction, or LLM-based embeddings
// are used. Multiple entries may be present when multiple LLM calls occur
// within one extraction (e.g. VLM OCR + structured extraction).
type LlmUsage struct {
	// The LLM model identifier (e.g. "openai/gpt-4o", "anthropic/claude-sonnet-4-20250514").
	Model string `json:"model"`
	// The pipeline stage that triggered this LLM call
	// (e.g. "vlm_ocr", "structured_extraction", "embeddings").
	Source string `json:"source"`
	// Number of input/prompt tokens consumed.
	InputTokens *uint64 `json:"input_tokens,omitempty"`
	// Number of output/completion tokens generated.
	OutputTokens *uint64 `json:"output_tokens,omitempty"`
	// Total tokens (input + output).
	TotalTokens *uint64 `json:"total_tokens,omitempty"`
	// Estimated cost in USD based on the provider's published pricing.
	EstimatedCost *float64 `json:"estimated_cost,omitempty"`
	// Why the model stopped generating (e.g. "stop", "length", "content_filter").
	FinishReason *string `json:"finish_reason,omitempty"`
}

// LlmUsage option function
type LlmUsageOption func(*LlmUsage)

