// Render a single PDF page to a PNG-encoded byte buffer.
//
// # Errors
//
// Returns an error if the PDF is invalid, the page index is out of bounds,
// or if the page fails to render.
//
// # Example
//
// ```rust,no_run
// use kreuzberg::pdf::render_pdf_page_to_png;
//
// # fn example() -> kreuzberg::pdf::error::Result<()> {
// let pdf_bytes = std::fs::read("document.pdf")?;
// let png = render_pdf_page_to_png(&pdf_bytes, 0, Some(150), None)?;
// std::fs::write("page_0.png", png)?;
// # Ok(())
// # }
// ```
func RenderPdfPageToPng(pdf_bytes []byte, page_index uint, dpi *int32, password *string) (*[]byte, error) {
	cPdfBytes := (*C.uint8_t)(unsafe.Pointer(&pdf_bytes[0]))
	cPdfBytesLen := C.uintptr_t(len(pdf_bytes))

	cPageIndex := C.size_t(uint(page_index))

	var cDpi C.int32_t = C.int32_t(int32(2147483647))
	if dpi != nil {
		cDpi = C.int32_t(int32(*dpi))
	}

	var cPassword *C.char
	if password != nil {
		cPassword = C.CString(*password)
		defer C.free(unsafe.Pointer(cPassword))
	}

	ptr := C.kreuzberg_render_pdf_page_to_png(cPdfBytes, cPdfBytesLen, cPageIndex, cDpi, cPassword)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.kreuzberg_free_string(ptr)
		}
		return nil, err
	}
	defer C.kreuzberg_free_string(ptr)
	return unmarshalBytes(ptr), nil
}

